    void WriteConfigSection(std::ofstream& file, const char* title, const std::vector<std::string>& values)
    {
        file << "[" << title << "]\r\n";
        for (const std::string& value : values)
        {
            file << value << "\r\n";
        }
        file << "\r\n";
    }

    void EnsureDefaultConfigFile(const std::wstring& path)
    {
        const DWORD attributes = GetFileAttributesW(path.c_str());
        if (attributes != INVALID_FILE_ATTRIBUTES && (attributes & FILE_ATTRIBUTE_DIRECTORY) == 0)
        {
            return;
        }

        std::ofstream file(path, std::ios::binary);
        if (!file)
        {
            throw std::runtime_error("无法创建配置文件。");
        }

        const unsigned char bom[] = { 0xEF, 0xBB, 0xBF };
        file.write(reinterpret_cast<const char*>(bom), sizeof(bom));
        file
            << "# Write_Prat_Attr configuration\r\n"
            << "# 每行一个选项；对话框打开时会重新读取这些分组并刷新枚举。\r\n\r\n";
        WriteConfigSection(file, "客户", DefaultCustomers());
        WriteConfigSection(file, "颜色", DefaultColors());
        WriteConfigSection(file, "材料", DefaultMaterials());
    }

    std::string Trim(const std::string& value)
    {
        size_t first = 0;
        while (first < value.size() && std::isspace(static_cast<unsigned char>(value[first])))
        {
            ++first;
        }

        size_t last = value.size();
        while (last > first && std::isspace(static_cast<unsigned char>(value[last - 1])))
        {
            --last;
        }

        return value.substr(first, last - first);
    }

    std::string RemoveUtf8Bom(const std::string& value)
    {
        if (value.size() >= 3 &&
            static_cast<unsigned char>(value[0]) == 0xEF &&
            static_cast<unsigned char>(value[1]) == 0xBB &&
            static_cast<unsigned char>(value[2]) == 0xBF)
        {
            return value.substr(3);
        }
        return value;
    }

    bool ContainsText(const std::vector<std::string>& values, const std::string& text)
    {
        for (const std::string& value : values)
        {
            if (value == text)
            {
                return true;
            }
        }
        return false;
    }

    void AddUniqueText(std::vector<std::string>& values, const std::string& text)
    {
        if (!text.empty() && !ContainsText(values, text))
        {
            values.push_back(text);
        }
    }

    struct DialogConfig
    {
        std::vector<std::string> customers;
        std::vector<std::string> colors;
        std::vector<std::string> materials;
    };

    enum class ConfigSection
    {
        None,
        Customers,
        Colors,
        Materials
    };

    DialogConfig LoadDialogConfig()
    {
        const std::wstring path = ConfigFilePath();
        EnsureDefaultConfigFile(path);

        std::ifstream file(path, std::ios::binary);
        if (!file)
        {
            throw std::runtime_error("无法读取配置文件。");
        }

        DialogConfig config;
        ConfigSection section = ConfigSection::None;
        std::string line;
        bool firstLine = true;
        while (std::getline(file, line))
        {
            if (firstLine)
            {
                line = RemoveUtf8Bom(line);
                firstLine = false;
            }

            const std::string value = Trim(line);
            if (value.empty() || value[0] == '#' || value[0] == ';')
            {
                continue;
            }

            if (value.front() == '[' && value.back() == ']')
            {
                const std::string sectionName = Trim(value.substr(1, value.size() - 2));
                if (sectionName == "客户")
                {
                    section = ConfigSection::Customers;
                }
                else if (sectionName == "颜色")
                {
                    section = ConfigSection::Colors;
                }
                else if (sectionName == "材料")
                {
                    section = ConfigSection::Materials;
                }
                else
                {
                    section = ConfigSection::None;
                }
                continue;
            }

            switch (section)
            {
            case ConfigSection::Customers:
                AddUniqueText(config.customers, value);
                break;
            case ConfigSection::Colors:
                AddUniqueText(config.colors, value);
                break;
            case ConfigSection::Materials:
                AddUniqueText(config.materials, value);
                break;
            default:
                break;
            }
        }

        if (config.customers.empty())
        {
            config.customers = DefaultCustomers();
        }
        if (config.colors.empty())
        {
            config.colors = DefaultColors();
        }
        if (config.materials.empty())
        {
            config.materials = DefaultMaterials();
        }

        return config;
    }

    std::string Utf8Text(const NXOpen::NXString& value)
    {
        const char* text = value.GetUTF8Text();
        return text == NULL ? std::string() : std::string(text);
    }

    std::vector<NXOpen::NXString> ToNxStrings(const std::vector<std::string>& values)
    {
        std::vector<NXOpen::NXString> result;
        result.reserve(values.size());
        for (const std::string& value : values)
        {
            result.push_back(NXOpen::NXString(value, NXOpen::NXString::UTF8));
        }
        return result;
    }

    void SetEnumValueIfPresent(NXOpen::BlockStyler::Enumeration* block, const std::vector<std::string>& values, const std::string& value)
    {
        if (block != NULL && ContainsText(values, value))
        {
            block->SetValueAsString(NXOpen::NXString(value, NXOpen::NXString::UTF8));
        }
    }

    void ApplyEnumMembers(NXOpen::BlockStyler::Enumeration* block, const std::vector<std::string>& values)
    {
        if (block == NULL)
        {
            throw std::runtime_error("未找到枚举控件。");
        }
        if (values.empty())
        {
            throw std::runtime_error("配置文件中的枚举选项不能为空。");
        }

        std::string previousValue;
        try
        {
            previousValue = Utf8Text(block->ValueAsString());
        }
        catch (...)
        {
            previousValue.clear();
        }

        std::vector<NXOpen::NXString> members = ToNxStrings(values);
        block->SetEnumMembers(members);

        if (ContainsText(values, previousValue))
        {
            block->SetValueAsString(NXOpen::NXString(previousValue, NXOpen::NXString::UTF8));
        }
        else
        {
            block->SetValueAsString(members.front());
        }
    }

    void SetEnumValueFromAttribute(
        NXOpen::Part* workPart,
        NXOpen::BlockStyler::Enumeration* block,
        const char* attributeName,
        const std::vector<std::string>& values)
    {
        const NXOpen::NXString title(attributeName, NXOpen::NXString::UTF8);
        if (workPart->HasUserAttribute(title, NXOpen::NXObject::AttributeType::AttributeTypeString, -1))
        {
            SetEnumValueIfPresent(
                block,
                values,
                Utf8Text(workPart->GetUserAttributeAsString(title, NXOpen::NXObject::AttributeType::AttributeTypeString, -1)));
        }
    }

