    bool IsPositiveInteger(const std::string& value)
    {
        if (value.empty())
        {
            return false;
        }

        bool hasNonZero = false;
        for (char ch : value)
        {
            if (!std::isdigit(static_cast<unsigned char>(ch)))
            {
                return false;
            }
            hasNonZero = hasNonZero || ch != '0';
        }
        return hasNonZero;
    }

