    std::string QuantityFromPartAttribute(NXOpen::Part* workPart)
    {
        const NXOpen::NXString title("数量", NXOpen::NXString::UTF8);
        if (workPart->HasUserAttribute(title, NXOpen::NXObject::AttributeType::AttributeTypeString, -1))
        {
            const std::string value = Trim(Utf8Text(workPart->GetUserAttributeAsString(title, NXOpen::NXObject::AttributeType::AttributeTypeString, -1)));
            if (IsPositiveInteger(value))
            {
                return value;
            }
        }
        return std::string();
    }

    bool SameBasePart(NXOpen::BasePart* lhs, NXOpen::BasePart* rhs)
    {
        if (lhs == NULL || rhs == NULL)
        {
            return false;
        }
        if (lhs == rhs)
        {
            return true;
        }

        const std::string lhsPath = Utf8Text(lhs->FullPath());
        const std::string rhsPath = Utf8Text(rhs->FullPath());
        if (!lhsPath.empty() && !rhsPath.empty() && lhsPath == rhsPath)
        {
            return true;
        }

        const std::string lhsLeaf = Utf8Text(lhs->Leaf());
        const std::string rhsLeaf = Utf8Text(rhs->Leaf());
        return !lhsLeaf.empty() && lhsLeaf == rhsLeaf;
    }

    bool ComponentMatchesPart(NXOpen::Assemblies::Component* component, NXOpen::BasePart* targetPart)
    {
        if (component == NULL || targetPart == NULL)
        {
            return false;
        }

        try
        {
            NXOpen::BasePart* prototypePart = dynamic_cast<NXOpen::BasePart*>(component->Prototype());
            if (SameBasePart(prototypePart, targetPart))
            {
                return true;
            }
        }
        catch (...)
        {
        }

        try
        {
            const std::string displayName = Utf8Text(component->DisplayName());
            const std::string targetLeaf = Utf8Text(targetPart->Leaf());
            return !displayName.empty() && !targetLeaf.empty() && displayName == targetLeaf;
        }
        catch (...)
        {
            return false;
        }
    }

    int CountPartOccurrences(NXOpen::Assemblies::Component* component, NXOpen::BasePart* targetPart)
    {
        if (component == NULL)
        {
            return 0;
        }

        try
        {
            if (component->IsComponentOrAncestorSuppressed())
            {
                return 0;
            }
        }
        catch (...)
        {
            try
            {
                if (component->IsSuppressed())
                {
                    return 0;
                }
            }
            catch (...)
            {
            }
        }

        int count = ComponentMatchesPart(component, targetPart) ? 1 : 0;
        std::vector<NXOpen::Assemblies::Component*> children;
        try
        {
            children = component->GetChildren();
        }
        catch (...)
        {
            return count;
        }

        for (NXOpen::Assemblies::Component* child : children)
        {
            count += CountPartOccurrences(child, targetPart);
        }
        return count;
    }

    std::string QuantityFromAssembly(NXOpen::Part* workPart)
    {
        try
        {
            NXOpen::Part* displayPart = CurrentDisplayPart();
            NXOpen::Part* assemblyPart = displayPart == NULL ? workPart : displayPart;
            NXOpen::Assemblies::ComponentAssembly* assembly = assemblyPart->ComponentAssembly();
            if (assembly == NULL)
            {
                return "1";
            }

            NXOpen::Assemblies::Component* root = assembly->RootComponent();
            if (root == NULL)
            {
                return "1";
            }

            const int count = CountPartOccurrences(root, workPart);
            return std::to_string(count > 0 ? count : 1);
        }
        catch (...)
        {
            return "1";
        }
    }

    std::string AutomaticQuantity(NXOpen::Part* workPart)
    {
        const std::string attributeQuantity = QuantityFromPartAttribute(workPart);
        if (!attributeQuantity.empty())
        {
            return attributeQuantity;
        }
        return QuantityFromAssembly(workPart);
    }

    void RefreshQuantityInput(
        NXOpen::BlockStyler::Toggle* manualQuantityBlock,
        NXOpen::BlockStyler::StringBlock* quantityBlock,
        NXOpen::Part* workPart)
    {
        const bool manualInput = ToggleValue(manualQuantityBlock);
        if (quantityBlock != NULL)
        {
            quantityBlock->SetEnable(manualInput);
        }
        if (!manualInput)
        {
            SetStringBlockValue(quantityBlock, AutomaticQuantity(workPart));
        }
    }

